WITH checkpoint_with_delta AS ( SELECT cr.checkpoint_raw_id AS id, cr.collected_at, cr.checkpoint_type AS type, cr.checkpoint_write_time, cr.checkpoint_sync_time, cr.wal_bytes, cr.checkpoint_distance, cr.buffers_checkpoint, cr.buffers_backend, cr.avg_buffers_per_sec, cr.wal_files_added, cr.wal_files_removed, -- 이전 값과의 차이 계산 (delta) CASE WHEN LAG(cr.checkpoint_write_time) OVER (PARTITION BY cr.instance_id ORDER BY cr.collected_at) IS NULL THEN 0.0 ELSE cr.checkpoint_write_time - LAG(cr.checkpoint_write_time) OVER (PARTITION BY cr.instance_id ORDER BY cr.collected_at) END AS delta_write_time, CASE WHEN LAG(cr.checkpoint_sync_time) OVER (PARTITION BY cr.instance_id ORDER BY cr.collected_at) IS NULL THEN 0.0 ELSE cr.checkpoint_sync_time - LAG(cr.checkpoint_sync_time) OVER (PARTITION BY cr.instance_id ORDER BY cr.collected_at) END AS delta_sync_time, -- 체크포인트 발생 여부 확인 CASE WHEN LAG(cr.checkpoints_timed) OVER (PARTITION BY cr.instance_id ORDER BY cr.collected_at) IS NULL THEN 0 ELSE cr.checkpoints_timed - LAG(cr.checkpoints_timed) OVER (PARTITION BY cr.instance_id ORDER BY cr.collected_at) END AS delta_timed, CASE WHEN LAG(cr.checkpoints_req) OVER (PARTITION BY cr.instance_id ORDER BY cr.collected_at) IS NULL THEN 0 ELSE cr.checkpoints_req - LAG(cr.checkpoints_req) OVER (PARTITION BY cr.instance_id ORDER BY cr.collected_at) END AS delta_req, -- 체크포인트 간격 계산 (분 단위): 이전 체크포인트와의 시간 차이 COALESCE( EXTRACT(EPOCH FROM (cr.collected_at - LAG(cr.collected_at) OVER (PARTITION BY cr.instance_id ORDER BY cr.collected_at))) / 60.0, 0.0 ) AS checkpoint_interval_minutes, -- WAL 제거 delta 계산 CASE WHEN LAG(cr.wal_files_removed) OVER (PARTITION BY cr.instance_id ORDER BY cr.collected_at) IS NULL THEN 0 ELSE GREATEST(cr.wal_files_removed - LAG(cr.wal_files_removed) OVER (PARTITION BY cr.instance_id ORDER BY cr.collected_at), 0) END AS delta_wal_files_removed, -- 버퍼 delta 계산 CASE WHEN LAG(cr.buffers_checkpoint) OVER (PARTITION BY cr.instance_id ORDER BY cr.collected_at) IS NULL THEN 0 ELSE GREATEST(cr.buffers_checkpoint - LAG(cr.buffers_checkpoint) OVER (PARTITION BY cr.instance_id ORDER BY cr.collected_at), 0) END AS delta_buffers_checkpoint FROM checkpoint_raw cr WHERE cr.instance_id = #{instanceId} AND cr.collected_at >= #{startTime} AND cr.collected_at <= #{endTime} ) SELECT id, TO_CHAR(collected_at AT TIME ZONE 'UTC' AT TIME ZONE 'Asia/Seoul', 'YYYY-MM-DD HH24:MI:SS') AS timestamp, CASE WHEN delta_req > 0 THEN 'requested' WHEN delta_timed > 0 THEN 'timed' ELSE 'unknown' END AS type, -- 체크포인트 간격 (분 단위, 소수점 2자리) CASE WHEN checkpoint_interval_minutes > 0 THEN ROUND(CAST(checkpoint_interval_minutes AS NUMERIC), 2) ELSE 0.0 END AS checkpointDistance, -- delta 값을 초 단위로 변환 (밀리초 -> 초) -- 체크포인트가 발생한 경우 delta를 계산 (음수 방지) CASE WHEN (delta_timed > 0 OR delta_req > 0) AND delta_write_time >= 0 THEN ROUND(CAST(GREATEST(delta_write_time, 0) / 1000.0 AS NUMERIC), 2) ELSE 0.0 END AS writeTime, CASE WHEN (delta_timed > 0 OR delta_req > 0) AND delta_sync_time >= 0 THEN ROUND(CAST(GREATEST(delta_sync_time, 0) / 1000.0 AS NUMERIC), 2) ELSE 0.0 END AS syncTime, CASE WHEN (delta_timed > 0 OR delta_req > 0) AND (delta_write_time >= 0 OR delta_sync_time >= 0) THEN ROUND(CAST((GREATEST(delta_write_time, 0) + GREATEST(delta_sync_time, 0)) / 1000.0 AS NUMERIC), 2) ELSE 0.0 END AS totalTime, CONCAT(ROUND(CAST(wal_bytes / 1048576.0 AS NUMERIC), 2), ' MB') AS walGenerated, COALESCE(wal_files_added, 0) AS walFilesAdded, -- WAL 제거는 delta 계산 delta_wal_files_removed AS walFilesRemoved, COALESCE(buffers_checkpoint, 0) AS buffersWritten, COALESCE(buffers_backend, 0) AS buffersBackend, -- 평균 버퍼 처리량: delta 버퍼 / delta 시간 (초당) CASE WHEN (delta_timed > 0 OR delta_req > 0) AND delta_write_time > 0 AND delta_buffers_checkpoint > 0 THEN ROUND(CAST(delta_buffers_checkpoint * 1000.0 / delta_write_time AS NUMERIC), 2) ELSE 0.0 END AS avgBuffersPerSec, -- 상태 판정: delta 총 시간 기준 CASE WHEN (delta_timed > 0 OR delta_req > 0) AND (delta_write_time + delta_sync_time) / 1000.0 > 30 THEN '위험' WHEN (delta_timed > 0 OR delta_req > 0) AND (delta_write_time + delta_sync_time) / 1000.0 > 15 THEN '주의' ELSE '정상' END AS status FROM checkpoint_with_delta WHERE (delta_timed > 0 OR delta_req > 0) -- 체크포인트가 발생한 경우만 표시
AND CASE WHEN delta_req > 0 THEN 'requested' WHEN delta_timed > 0 THEN 'timed' ELSE 'unknown' END IN
#{type}
AND CASE WHEN (delta_timed > 0 OR delta_req > 0) AND (delta_write_time + delta_sync_time) / 1000.0 > 30 THEN '위험' WHEN (delta_timed > 0 OR delta_req > 0) AND (delta_write_time + delta_sync_time) / 1000.0 > 15 THEN '주의' ELSE '정상' END IN
#{status}
ORDER BY collected_at DESC
